commands:
$path = '.\smart_label.py'; $txt = Get-Content $path -Raw; if ($txt -notmatch 'def get_base_dir\(') { $insert = @"
def get_base_dir():
    """Get the base directory of the application"""
    return os.path.dirname(os.path.abspath(__file__))

"@; $txt = $txt -replace '(from typing import [^\r\n]+\r?\n)', '`$1`r`n$insert'; Set-Content -Path $path -Value $txt -Encoding UTF8; 'Patched get_base_dir in smart_label.py' }
